tasks.description:
Set up the DataLoader infrastructure for the GraphQL API.

**1. Install dataloader:**
```bash
pnpm --filter api add dataloader
```

**2. Create `apps/api/src/graphql/loaders.ts`:**

```typescript
import DataLoader from 'dataloader';
import { PrismaClient } from '@prisma/client';

export interface Loaders {
  taskById: DataLoader<string, Task | null>;
  projectById: DataLoader<string, Project | null>;
  sprintById: DataLoader<string, Sprint | null>;
  userById: DataLoader<string, User | null>;
  taskLabels: DataLoader<string, Label[]>;
  taskPullRequests: DataLoader<string, PullRequestLink[]>;
  taskCommits: DataLoader<string, CommitLink[]>;
  taskChildren: DataLoader<string, Task[]>;
  taskProgress: DataLoader<string, { total: number; completed: number } | null>;
  sprintTasks: DataLoader<string, Task[]>;
}

export function createLoaders(prisma: PrismaClient): Loaders {
  return {
    taskById: new DataLoader(async (ids) => {
      const tasks = await prisma.task.findMany({ where: { taskId: { in: [...ids] } } });
      const map = new Map(tasks.map(t => [t.taskId, t]));
      return ids.map(id => map.get(id) ?? null);
    }),

    projectById: new DataLoader(async (ids) => {
      const projects = await prisma.project.findMany({ where: { projectId: { in: [...ids] } } });
      const map = new Map(projects.map(p => [p.projectId, p]));
      return ids.map(id => map.get(id) ?? null);
    }),

    sprintById: new DataLoader(async (ids) => {
      const sprints = await prisma.sprint.findMany({ where: { sprintId: { in: [...ids] } } });
      const map = new Map(sprints.map(s => [s.sprintId, s]));
      return ids.map(id => map.get(id) ?? null);
    }),

    userById: new DataLoader(async (ids) => {
      const users = await prisma.user.findMany({ where: { userId: { in: [...ids] } } });
      const map = new Map(users.map(u => [u.userId, u]));
      return ids.map(id => map.get(id) ?? null);
    }),

    taskLabels: new DataLoader(async (taskIds) => {
      const taskLabels = await prisma.taskLabel.findMany({
        where: { taskId: { in: [...taskIds] } },
        include: { label: true }
      });
      const map = new Map<string, Label[]>();
      for (const tl of taskLabels) {
        if (!map.has(tl.taskId)) map.set(tl.taskId, []);
        map.get(tl.taskId)!.push(tl.label);
      }
      return taskIds.map(id => map.get(id) ?? []);
    }),

    taskPullRequests: new DataLoader(async (taskIds) => {
      const prs = await prisma.gitHubPullRequestLink.findMany({
        where: { taskId: { in: [...taskIds] } }
      });
      const map = new Map<string, typeof prs>();
      for (const pr of prs) {
        if (!map.has(pr.taskId)) map.set(pr.taskId, []);
        map.get(pr.taskId)!.push(pr);
      }
      return taskIds.map(id => map.get(id) ?? []);
    }),

    taskCommits: new DataLoader(async (taskIds) => {
      const commits = await prisma.gitHubCommitLink.findMany({
        where: { taskId: { in: [...taskIds] } }
      });
      const map = new Map<string, typeof commits>();
      for (const c of commits) {
        if (!map.has(c.taskId)) map.set(c.taskId, []);
        map.get(c.taskId)!.push(c);
      }
      return taskIds.map(id => map.get(id) ?? []);
    }),

    taskChildren: new DataLoader(async (parentIds) => {
      const children = await prisma.task.findMany({
        where: { parentTaskId: { in: [...parentIds] }, archived: false },
        orderBy: { position: 'asc' }
      });
      const map = new Map<string, typeof children>();
      for (const c of children) {
        if (!map.has(c.parentTaskId!)) map.set(c.parentTaskId!, []);
        map.get(c.parentTaskId!)!.push(c);
      }
      return parentIds.map(id => map.get(id) ?? []);
    }),

    taskProgress: new DataLoader(async (taskIds) => {
      // For epics/stories: count total and completed children
      const children = await prisma.task.findMany({
        where: { parentTaskId: { in: [...taskIds] }, archived: false },
        select: { parentTaskId: true, status: true }
      });
      const map = new Map<string, { total: number; completed: number }>();
      for (const c of children) {
        if (!map.has(c.parentTaskId!)) map.set(c.parentTaskId!, { total: 0, completed: 0 });
        const p = map.get(c.parentTaskId!)!;
        p.total++;
        if (c.status === 'done') p.completed++;
      }
      return taskIds.map(id => map.get(id) ?? null);
    }),

    sprintTasks: new DataLoader(async (sprintIds) => {
      const tasks = await prisma.task.findMany({
        where: { sprintId: { in: [...sprintIds] }, parentTaskId: null }
      });
      const map = new Map<string, typeof tasks>();
      for (const t of tasks) {
        if (!t.sprintId) continue;
        if (!map.has(t.sprintId)) map.set(t.sprintId, []);
        map.get(t.sprintId)!.push(t);
      }
      return sprintIds.map(id => map.get(id) ?? []);
    }),
  };
}
```

Use the actual Prisma-generated types — import them from `@prisma/client`. The loader return types should match what the field resolvers currently return.

**3. Update Context (`apps/api/src/graphql/context.ts`):**

Add `loaders` to the Context interface:
```typescript
import { createLoaders, Loaders } from './loaders.js';

export interface Context {
  user: { ... } | null;
  org: { ... } | null;
  prisma: PrismaClient;
  loaders: Loaders;
}
```

In `buildContext`, create loaders per request:
```typescript
return { user: ..., org: ..., prisma, loaders: createLoaders(prisma) };
```
Do this in ALL return paths (including unauthenticated returns).

**Verification:** `pnpm --filter api typecheck` passes.

Cache GitHub API responses to reduce rate limit risk and improve latency.

**1. Create a simple cache utility (`apps/api/src/github/githubCache.ts`):**
```typescript
interface CacheEntry<T> {
  data: T;
  expiresAt: number;
}

const cache = new Map<string, CacheEntry<unknown>>();

export function getCached<T>(key: string): T | null {
  const entry = cache.get(key);
  if (!entry || Date.now() > entry.expiresAt) {
    cache.delete(key);
    return null;
  }
  return entry.data as T;
}

export function setCache<T>(key: string, data: T, ttlMs: number): void {
  cache.set(key, { data, expiresAt: Date.now() + ttlMs });
  // Simple eviction: if cache gets too large, clear oldest entries
  if (cache.size > 200) {
    const firstKey = cache.keys().next().value;
    if (firstKey) cache.delete(firstKey);
  }
}

export function invalidateCache(prefix: string): void {
  for (const key of cache.keys()) {
    if (key.startsWith(prefix)) cache.delete(key);
  }
}
```

**2. Add caching to `apps/api/src/github/githubRepositoryService.ts`:**
- `listInstallationRepos(installationId)` — cache with key `repos:${installationId}`, TTL 1 hour
- Check cache before API call, store result after

**3. Add caching to `apps/api/src/github/githubFileService.ts`:**
- `fetchProjectFileTree(repo)` — cache with key `filetree:${owner}:${name}`, TTL 6 hours

**4. Invalidate on webhook (`apps/api/src/github/githubWebhookHandler.ts`):**
- On `push` events, call `invalidateCache('filetree:' + owner + ':' + repo)`
- On `installation` events, call `invalidateCache('repos:' + installationId)`

**Verification:** `pnpm --filter api typecheck` passes.

Production performance and build config improvements.

**1. Add compression middleware (`apps/api/src/app.ts`):**
```bash
pnpm --filter api add compression && pnpm --filter api add -D @types/compression
```
Then add to Express stack after body parsing, before routes:
```typescript
import compression from 'compression';
app.use(compression());
```
Place it before the export router and GraphQL middleware.

**2. Configure Vite chunk splitting (`apps/web/vite.config.ts`):**
Add build optimization:
```typescript
export default defineConfig({
  plugins: [react()],
  build: {
    rollupOptions: {
      output: {
        manualChunks: {
          react: ['react', 'react-dom'],
          router: ['react-router-dom'],
        },
      },
    },
  },
  server: { ... }
});
```
This splits React and Router into separate chunks for better browser caching.

**3. Fix pnpm-workspace.yaml:**
Remove the non-existent `packages/*` entry:
```yaml
packages:
  - "apps/*"
  - "infra"
```

**Verification:** `pnpm build` passes, `pnpm --filter web build` produces split chunks.
